DEO173" class="ladi-element"><div class='ladi-video'><div class="ladi-video-background"></div><div  id="SHAPE173" class="ladi-element"><div class='ladi-shape'><svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" preserveAspectRatio="none" viewBox="0 0 408.7 408.7" fill="rgba(0, 0, 0, 0.5)"><polygon fill="#fff" points="163.5 296.3 286.1 204.3 163.5 112.4 163.5 296.3"></polygon><path d="M204.3,0C91.5,0,0,91.5,0,204.3S91.5,408.7,204.3,408.7s204.3-91.5,204.3-204.3S316.7,0,204.3,0ZM163.5,296.3V112.4l122.6,91.9Z" transform="translate(0 0)"></path></svg></div></div></div></div><div data-action="true" id="BUTTON174" class="ladi-element"><div class='ladi-button'><div class="ladi-button-background"></div><div  id="BUTTON_TEXT174" class="ladi-element"><p class='ladi-headline'>ĐĂNG KÝ NGAY</p></div></div></div></div></div><div id="SECTION377" class="ladi-section"><div class='ladi-section-background'></div><div class="ladi-container"><div  id="GROUP422" class="ladi-element"><div class='ladi-group'><div  id="BOX404" class="ladi-element"><div class='ladi-box'></div></div><div  id="HEADLINE380" class="ladi-element"><h6 class='ladi-headline'>Sơ tuyển đầu vào</h6></div><div  id="PARAGRAPH381" class="ladi-element"><p class='ladi-paragraph'>Tiêu chí tuyển dụng: Ngoại hình, sức khỏe, thể lực, độ tuổi, trình độ học vấn, kinh nghiệm chuyên môn.</p></div><div  id="IMAGE382" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div></div></div><div  id="GROUP421" class="ladi-element"><div class='ladi-group'><div  id="BOX407" class="ladi-element"><div class='ladi-box'></div></div><div  id="HEADLINE393" class="ladi-element"><h6 class='ladi-headline'>Đào tạo nâng cao</h6></div><div  id="PARAGRAPH394" class="ladi-element"><p class='ladi-paragraph'>Sau trúng tuyển, TTS được đào tạo nhằm nâng cao tiếng Nhật, kiến thức chuyên môn, tay nghề để đảm bảo việc thực tập tại Nhật</p></div><div  id="IMAGE395" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div></div></div><div  id="GROUP420" class="ladi-element"><div class='ladi-group'><div  id="BOX408" class="ladi-element"><div class='ladi-box'></div></div><div  id="HEADLINE397" class="ladi-element"><h6 class='ladi-headline'>Hoàn tất thủ tục, tư cách lưu trú, visa</h6></div><div  id="PARAGRAPH398" class="ladi-element"><p class='ladi-paragraph'>Nộp đơn xin cấp thị thực cho đại sứ quán Nhật Bản theo dạng visa hoặc giấy phép lao động cho thực tập sinh</p></div><div  id="IMAGE399" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div></div></div><div  id="GROUP419" class="ladi-element"><div class='ladi-group'><div  id="BOX409" class="ladi-element"><div class='ladi-box'></div></div><div  id="HEADLINE401" class="ladi-element"><h6 class='ladi-headline'>Xuất cảnh, học tập và làm việc tại Nhật</h6></div><div  id="PARAGRAPH402" class="ladi-element"><p class='ladi-paragraph'>TTS sau khi sang Nhật 2-4 tuần: đào tạo có lương tại nghiệp đoàn để làm quen môi trường, văn hóa Nhật. Xí nghiệp, công ty Nhật đào tạo về công việc.</p></div><div  id="IMAGE403" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div></div></div><div  id="GROUP423" class="ladi-element"><div class='ladi-group'><div  id="BOX405" class="ladi-element"><div class='ladi-box'></div></div><div  id="HEADLINE385" class="ladi-element"><h6 class='ladi-headline'>Đào tạo trước thi tuyển</h6></div><div  id="PARAGRAPH386" class="ladi-element"><p class='ladi-paragraph'>Thực tập sinh sẽ được đào tạo miễn phí: tiếng Nhật phục vụ phỏng vấn, tay nghề, phong tục tập quán Nhật Bản</p></div><div  id="IMAGE387" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div></div></div><div  id="GROUP424" class="ladi-element"><div class='ladi-group'><div  id="BOX406" class="ladi-element"><div class='ladi-box'></div></div><div  id="HEADLINE389" class="ladi-element"><h6 class='ladi-headline'>Thi tuyển, phỏng vấn</h6></div><div  id="PARAGRAPH390" class="ladi-element"><p class='ladi-paragraph'>Doanh nghiệp Nhật Bản: Phỏng vấn trực tiếp hoặc qua skype Bài thi thể lực, kỹ năng và tay nghề theo từng đơn hàng</p></div><div  id="IMAGE391" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div></div></div><div  id="HEADLINE378" class="ladi-element"><h2 class='ladi-headline'>Quy trình tuyển dụng của Nozomi Japan</h2></div><div  id="PARAGRAPH383" class="ladi-element"><p class='ladi-paragraph'>Là đơn vị uy tín số 1 Việt Nam về xuất khẩu lao động nhật, quy trình làm việc của chúng tôi luôn đảm bảo sự minh bạch, chặt chẽ.</p></div></div></div><div id="SECTION425" class="ladi-section"><div class='ladi-section-background'></div><div class="ladi-overlay"></div><div class="ladi-container"><div  id="HEADLINE507" class="ladi-element"><h2 class='ladi-headline'>Cơ sở vật chất của chúng tôi</h2></div><div  id="BUTTON509" class="ladi-element"><div class='ladi-button'><div class="ladi-button-background"></div><div  id="BUTTON_TEXT509" class="ladi-element"><p class='ladi-headline'>ĐĂNG KÝ NGAY</p></div></div></div><div  id="IMAGE432" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div><div  id="IMAGE433" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div><div  id="IMAGE434" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div><div  id="IMAGE435" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div></div></div><div  id="IMAGE427" class="ladi-element"><div class='ladi-image'><div class="ladi-image-background"></div><div class="ladi-overlay"></div></div></div></div></div><div id="SECTION436" class="ladi-section"><div class='ladi-section-background'></div><div class="ladi-overlay"></div><div class="ladi-container"><div  id="GROUP461" class="ladi-element"><div class='ladi-group'><div  id="HEADLINE462" class="ladi-element"><h3 class='ladi-headline'>Nozomi Japan hỗ trợ thực tập sinh những gì?</h3></div><div  id="PARAGRAPH463" class="ladi-element"><p class='ladi-paragraph'>Thực tập sinh của Nozomi luôn nhận được nhiều sự hỗ trợ</p></div></div></div><div id="LINE464" class="ladi-element"><div class='ladi-line'><div class="ladi-line-container"></div></div></div><div  id="GROUP465" class="ladi-element"><div class='ladi-group'><div  id="SHAPE466" class="ladi-element"><div class='ladi-shape'><svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" preserveAspectRatio="none" viewBox="0 0 1664 1896.0833" class="" fill="rgba(239, 246, 255, 1.0)"> <path d="M1639 478q40 57 18 129l-275 906q-19 64-76.5 107.5T1183 1664H260q-77 0-148.5-53.5T12 1479q-24-67-2-127 0-4 3-27t4-37q1-8-3-21.5t-3-19.5q2-11 8-21t16.5-23.5T52 1179q23-38 45-91.5t30-91.5q3-10 .5-30t-.5-28q3-11 17-28t17-23q21-36 42-92t25-90q1-9-2.5-32t.5-28q4-13 22-30.5t22-22.5q19-26 42.5-84.5T340 411q1-8-3-25.5t-2-26.5q2-8 9-18t18-23 17-21q8-12 16.5-30.5t15-35 16-36 19.5-32 26.5-23.5 36-11.5T556 134l-1 3q38-9 51-9h761q74 0 114 56t18 130l-274 906q-36 119-71.5 153.5T1025 1408H156q-27 0-38 15-11 16-1 43 24 70 144 70h923q29 0 56-15.5t35-41.5l300-987q7-22 5-57 38 15 59 43zm-1064 2q-4 13 2 22.5t20 9.5h608q13 0 25.5-9.5T1247 480l21-64q4-13-2-22.5t-20-9.5H638q-13 0-25.5 9.5T596 416zm-83 256q-4 13 2 22.5t20 9.5h608q13 0 25.5-9.5T1164 736l21-64q4-13-2-22.5t-20-9.5H555q-13 0-25.5 9.5T513 672z"></path> </svg></div></div><div  id="HEADLINE467" class="ladi-element"><h3 class='ladi-headline'><span style="font-weight: 400;">Miễn phí học đến khi trúng tuyển</span><br></h3></div><div id="LINE468" class="ladi-element"><div class='ladi-line'><div class="ladi-line-container"></div></div></div></div></div><div  id="GROUP469" class="ladi-element"><div class='ladi-group'><div  id="SHAPE470" class="ladi-element"><div class='ladi-shape'><svg xmlns="http://www.w3.org/2000/svg" width="1